#include<cstdio>
#include<vector>
#include<map>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
map<int,vector<int> > mp;int x,n,a[20];
inline void dfs0(int p=0,int w=0,int S=0)
{
	if(p==x){mp[w].push_back(S);return;}
	dfs0(p+1,w+a[p],S|(1<<p));dfs0(p+1,w-a[p],S|(1<<p));dfs0(p+1,w,S);
}
bool vis[1<<20];
inline void dfs1(int p=x,int w=0,int S=0)
{
	if(p==n){vector<int> &vv=mp[w];for(int v:vv)vis[S|v]=true;return;}
	dfs1(p+1,w+a[p],S|(1<<p));dfs1(p+1,w-a[p],S|(1<<p));dfs1(p+1,w,S);
}
int main()
{
	n=read();for(int i=0;i<n;++i)a[i]=read();x=n>>1;dfs0();dfs1();
	int ans=0;for(int S=1;S<(1<<n);++S)ans+=vis[S];printf("%d\n",ans);
}
